      "follow_a_red_blood_cell_through_the_en": "Segui un globulo rosso attraverso l'intero sistema circolatorio.",
      "right_atrium": "Atrio destro",
      "deoxygenated_blood_from_the_body_enter": "Il sangue deossigenato del corpo entra nell'atrio destro tramite le vene cave superiore e inferiore.",
      "right_ventricle": "Ventricolo destro",
      "blood_passes_through_the_tricuspid_val": "Il sangue passa attraverso la valvola tricuspide nel ventricolo destro, che lo pompa verso i polmoni.",
      "pulmonary_arteries_2": "Arterie polmonari",
      "the_right_ventricle_ejects_blood_throu": "Il ventricolo destro espelle il sangue attraverso la valvola polmonare nelle arterie polmonari verso entrambi i polmoni.",
      "lung_capillaries": "Capillari polmonari",
      "in_the_alveolar_capillaries_co2_is_rel": "Nei capillari alveolari, la CO2 viene rilasciata e l'O2 viene captato attraverso la sottile membrana alveolare.",
      "pulmonary_veins": "Vene polmonari",
      "freshly_oxygenated_blood_returns_to_th": "Il sangue appena ossigenato torna al cuore tramite le quattro vene polmonari.",
      "left_atrium": "Atrio sinistro",
      "the_four_pulmonary_veins_empty_oxygena": "Le quattro vene polmonari svuotano il sangue ossigenato nell'atrio sinistro, che si riempie e poi lo spinge attraverso la valvola mitrale.",
      "left_ventricle": "Ventricolo sinistro",
      "blood_passes_through_the_mitral_valve_": "Il sangue passa attraverso la valvola mitrale nel muscoloso ventricolo sinistro, la camera cardiaca più forte.",
      "aorta_2": "Aorta",
      "the_left_ventricle_powerfully_ejects_b": "Il ventricolo sinistro espelle con forza il sangue attraverso la valvola aortica nell'aorta, l'autostrada principale del corpo.",
      "body_tissues": "Tessuti corporei",
      "arteries_branch_into_arterioles_and_ca": "Le arterie si ramificano in arteriole e capillari dove O2 e nutrienti vengono forniti e CO2/rifiuti raccolti.",
      "venous_return": "Ritorno venoso",
      "deoxygenated_blood_returns_through_ven": "Il sangue deossigenato torna attraverso venule e vene, aiutato da pompe muscolari e valvole, all'atrio destro.",
      "path_of_air": "Percorso dell'aria",
      "trace_the_journey_of_a_breath_of_air_f": "Traccia il viaggio di un respiro d'aria dal naso agli alveoli e ritorno.",
      "nasal_cavity_2": "Cavità nasale",
      "air_enters_through_the_nostrils_and_is": "L'aria entra dalle narici e viene riscaldata, umidificata e filtrata dalle mucose e dai turbinati.",
      "pharynx_2": "Faringe",
      "air_passes_through_the_nasopharynx_and": "L'aria passa attraverso il rinofaringe e l'orofaringe, un passaggio condiviso con il tratto digestivo.",
      "larynx": "Laringe",
      "air_crosses_the_vocal_cords_in_the_voi": "L'aria attraversa le corde vocali nell'organo della voce. L'epiglottide protegge dall'ingresso di cibo nelle vie aeree.",
      "trachea_2": "Trachea",
      "the_trachea_windpipe_is_reinforced_by_": "La trachea è rinforzata da anelli di cartilagine a forma di C. Le ciglia spingono il muco verso l'alto per intrappolare i detriti.",
      "bronchi": "Bronchi",
      "the_trachea_splits_into_left_and_right": "La trachea si divide nei bronchi principali sinistro e destro, ognuno entrando in un polmone. Si ramificano in bronchioli più piccoli.",
      "alveoli_2": "Alveoli",
      "300_million_grape_like_sacs_where_gas_": "300 milioni di sacchi simili a chicchi d'uva dove avviene lo scambio gassoso. L'O2 diffonde nel sangue; la CO2 diffonde all'esterno. La superficie equivale a un campo da tennis.",
      "exhalation": "Espirazione",
      "the_diaphragm_relaxes_and_rises_reduci": "Il diaframma si rilassa e sale, riducendo il volume polmonare. L'aria ricca di CO2 viene spinta fuori dallo stesso percorso al contrario.",
      "path_of_food": "Percorso del cibo",
      "follow_a_meal_from_mouth_through_the_e": "Segui un pasto dalla bocca attraverso l'intero sistema digestivo.",
      "mouth": "Bocca",
      "teeth_mechanically_break_food_down_sal": "I denti frantumano meccanicamente il cibo. L'amilasi salivare inizia la digestione dell'amido. La lingua modella il cibo in un bolo.",
      "pharynx_esophagus": "Faringe ed esofago",
      "swallowing_pushes_the_bolus_past_the_e": "La deglutizione spinge il bolo oltre l'epiglottide. Le onde peristaltiche lo fanno scendere lungo l'esofago di 25 cm in circa 8 secondi.",
      "stomach_2": "Stomaco",
      "gastric_acid_ph_1_5_3_5_and_pepsin_bre": "L'acido gastrico (pH 1,5-3,5) e la pepsina scompongono le proteine. Il rimescolamento produce il chimo in 2-4 ore.",
      "duodenum": "Duodeno",
      "the_first_25cm_of_the_small_intestine_": "I primi 25 cm dell'intestino tenue ricevono la bile dal fegato/cistifellea e gli enzimi dal pancreas.",
      "jejunum_ileum": "Digiuno e ileo",
      "most_nutrient_absorption_occurs_here_v": "Qui avviene la maggior parte dell'assorbimento dei nutrienti tramite villi e microvilli, aumentando la superficie di 600 volte. Lungo 6-7 metri.",
      "large_intestine_2": "Intestino crasso",
      "water_and_electrolytes_are_reabsorbed_": "Acqua ed elettroliti vengono riassorbiti. I batteri intestinali fermentano le fibre rimanenti, producendo le vitamine K e B12.",
      "rectum_excretion": "Retto ed escrezione",
      "waste_is_compacted_and_stored_in_the_r": "I rifiuti vengono compattati e immagazzinati nel retto fino alla defecazione. L'intero viaggio richiede 24-72 ore.",
      "path_of_a_nerve_signal": "Percorso di un segnale nervoso",
      "trace_a_reflex_arc_from_stimulus_to_re": "Traccia un arco riflesso dallo stimolo alla risposta.",
      "receptor": "Recettore",
      "a_sensory_receptor_in_the_skin_detects": "Un recettore sensoriale nella pelle rileva uno stimolo doloroso (come toccare una superficie calda) e genera un segnale elettrico.",
      "sensory_neuron": "Neurone sensoriale",
      "the_signal_travels_along_a_sensory_aff": "Il segnale viaggia lungo un neurone sensoriale (afferente) verso il midollo spinale fino a 120 m/s tramite conduzione saltatoria.",
      "spinal_cord_2": "Midollo spinale",
      "in_the_dorsal_horn_the_sensory_neuron_": "Nel corno dorsale, il neurone sensoriale fa sinapsi con un interneurone. Per i riflessi, il segnale non deve raggiungere il cervello.",
      "interneuron": "Interneurone",
      "the_interneuron_in_the_spinal_gray_mat": "L'interneurone nella sostanza grigia midollare integra il segnale e lo trasmette a un motoneurone.",
      "motor_neuron": "Motoneurone",
      "the_motor_efferent_neuron_carries_the_": "Il motoneurone (efferente) porta il segnale di comando dal corno ventrale fino al muscolo bersaglio.",
      "effector_muscle": "Effettore (muscolo)",
      "acetylcholine_released_at_the_neuromus": "L'acetilcolina rilasciata alla giunzione neuromuscolare provoca la contrazione muscolare. Ritiri la mano prima di sentire il dolore.",
      "brain_awareness": "Consapevolezza cerebrale",
